export function areaName(code: unknown, isoHint?: unknown, desc?: unknown): string {
  if (typeof desc === 'string' && desc.trim()) return desc.trim();
  const c = String(code ?? '').trim();
  if (c && COMTRADE_AREAS[c]) return COMTRADE_AREAS[c];
  if (typeof isoHint === 'string' && isoHint.trim()) return isoHint.trim();
  return c || 'Unknown';
}

export function areaIso(code: unknown, isoHint?: unknown): string | undefined {
  if (typeof isoHint === 'string' && /^[A-Za-z]{3}$/.test(isoHint.trim())) return isoHint.trim().toUpperCase();
  const c = String(code ?? '').trim();
  return c ? COMTRADE_ISO3[c] : undefined;
}
